import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const GEMINI_MODEL = 'gemini-3-pro-preview';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `You are the "Self-Speak Engine", an advanced linguistic AI designed to help adults learn a new language by focusing strictly on their own identity, life, and interests.

YOUR GOAL:
Generate a personalized "Day 1" language profile for the user. This includes a 60-second introduction script in their target language, a breakdown of personalized vocabulary, and a set of "Identity Tags".

INPUT:
User profile data including: Target Language, Profession, Passion, Motivation, and Personality.

OUTPUT FORMAT:
Return strictly a JSON object. Do not include markdown fences. The JSON must match this schema:

{
  "targetLanguage": "string",
  "nativeLanguage": "string",
  "identityTitle": "string (e.g., 'The Creative Architect' or 'The Wandering Chef')",
  "script": {
    "target": "string (A 60-second monologue in the target language. First person. Present tense. Simple but authentic.)",
    "phonetic": "string (Phonetic pronunciation guide)",
    "native": "string (English translation)"
  },
  "vocabulary": [
    {
      "term": "string (Target word)",
      "native": "string (English meaning)",
      "type": "string (One of: 'Identity', 'Action', 'Connector', 'Descriptor')"
    }
  ],
  "challenge": "string (A specific instruction for their first recording)"
}

DESIGN PRINCIPLES:
1. **Hyper-Relevance**: If the user is a UX Designer, use words like "design", "user", "interface" immediately.
2. **Foundational Fluency**: Mix these personal words with the top 100 most frequent verbs/connectors (is, have, want, go, because, but).
3. **Emotional Ownership**: The script should feel like "them". It should express their motivation clearly.

EXAMPLE INPUT:
Language: Spanish. Job: Nurse. Passion: Hiking. Motivation: Travel to Peru.
EXAMPLE SCRIPT START:
"Hola, soy Sarah. Soy enfermera. Me gusta ayudar a la gente. En mi tiempo libre, camino por las montañas..."`;

export interface UserProfile {
  targetLanguage: string;
  profession: string;
  passion: string;
  motivation: string;
  personality: string;
}

export async function generateIdentityProfile(profile: UserProfile): Promise<string> {
  const prompt = `
    Target Language: ${profile.targetLanguage}
    Profession: ${profile.profession}
    Passion: ${profile.passion}
    Motivation: ${profile.motivation}
    Personality/Traits: ${profile.personality}

    Generate the Self-Speak Profile JSON.
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: {
        parts: [{ text: prompt }]
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        temperature: 0.4, 
      },
    });

    let text = response.text || "{}";
    // Cleanup just in case, though responseMimeType usually handles it
    text = text.replace(/^```json\s*/, '').replace(/^```\s*/, '').replace(/```$/, '');

    return text;
  } catch (error) {
    console.error("Gemini Generation Error:", error);
    throw error;
  }
}

