import React, { useState, useRef, useEffect, useMemo, useCallback } from 'react';
import { MicrophoneIcon, SpeakerWaveIcon, ArrowPathIcon, ShareIcon, BookOpenIcon, PlayIcon, StopIcon } from '@heroicons/react/24/solid';

interface LivePreviewProps {
  creation: any; // Using any for the JSON structure
  isLoading: boolean;
  isFocused: boolean;
  onReset: () => void;
}

const AudioRecorder = () => {
    const [isRecording, setIsRecording] = useState(false);
    const [audioBlob, setAudioBlob] = useState<Blob | null>(null);
    const mediaRecorderRef = useRef<MediaRecorder | null>(null);
    const chunksRef = useRef<Blob[]>([]);

    const startRecording = async () => {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            mediaRecorderRef.current = new MediaRecorder(stream);
            chunksRef.current = [];

            mediaRecorderRef.current.ondataavailable = (e) => {
                if (e.data.size > 0) chunksRef.current.push(e.data);
            };

            mediaRecorderRef.current.onstop = () => {
                const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
                setAudioBlob(blob);
                // Stop all tracks to release mic
                stream.getTracks().forEach(track => track.stop());
            };

            mediaRecorderRef.current.start();
            setIsRecording(true);
        } catch (err) {
            console.error("Error accessing microphone:", err);
            alert("Microphone access is needed to record your practice.");
        }
    };

    const stopRecording = () => {
        if (mediaRecorderRef.current && isRecording) {
            mediaRecorderRef.current.stop();
            setIsRecording(false);
        }
    };

    const playRecording = () => {
        if (audioBlob) {
            const url = URL.createObjectURL(audioBlob);
            const audio = new Audio(url);
            audio.play();
        }
    };

    return (
        <div className="flex items-center space-x-4 bg-zinc-900/50 p-4 rounded-xl border border-zinc-800">
            <button
                onClick={isRecording ? stopRecording : startRecording}
                className={`w-12 h-12 rounded-full flex items-center justify-center transition-all ${isRecording ? 'bg-red-500 animate-pulse' : 'bg-zinc-800 hover:bg-zinc-700 text-white'}`}
            >
                {isRecording ? <StopIcon className="w-6 h-6 text-white" /> : <MicrophoneIcon className="w-6 h-6" />}
            </button>
            <div className="flex-1">
                <div className="text-sm font-medium text-white">{isRecording ? "Recording..." : audioBlob ? "Recording Saved" : "Record your script"}</div>
                <div className="text-xs text-zinc-500">{isRecording ? "Speak clearly..." : audioBlob ? "Click play to listen" : "Press the mic to start"}</div>
            </div>
            {audioBlob && !isRecording && (
                <button onClick={playRecording} className="p-2 text-blue-400 hover:text-blue-300">
                    <PlayIcon className="w-8 h-8" />
                </button>
            )}
        </div>
    );
};

export const LivePreview: React.FC<LivePreviewProps> = ({ creation, isLoading, isFocused, onReset }) => {
    const [activeTab, setActiveTab] = useState<'script' | 'vocab'>('script');
    const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);
    const [highlightedIndex, setHighlightedIndex] = useState<number | null>(null);

    // Load voices
    useEffect(() => {
        const updateVoices = () => {
            const available = window.speechSynthesis.getVoices();
            if (available.length > 0) {
                setVoices(available);
            }
        };
        updateVoices();
        window.speechSynthesis.onvoiceschanged = updateVoices;
        return () => { window.speechSynthesis.onvoiceschanged = null; };
    }, []);

    // Parse creation content if it's a JSON string
    const data = useMemo(() => {
        if (!creation || !creation.html) return null;
        try {
            return JSON.parse(creation.html);
        } catch (e) {
            console.error("Failed to parse creation JSON", e);
            return null;
        }
    }, [creation]);

    // Tokenize words for interactive highlighting
    const targetWords = useMemo(() => {
        if (!data?.script?.target) return [];
        return data.script.target.trim().split(/\s+/);
    }, [data]);

    const phoneticWords = useMemo(() => {
        if (!data?.script?.phonetic) return [];
        return data.script.phonetic.trim().split(/\s+/);
    }, [data]);

    const getVoiceForLanguage = useCallback((langName: string) => {
        if (!voices.length) return null;

        const normalized = langName.toLowerCase();
        let code = 'en'; // Default

        // Basic mapping for common languages
        if (normalized.includes('spanish') || normalized.includes('español')) code = 'es';
        else if (normalized.includes('french') || normalized.includes('français')) code = 'fr';
        else if (normalized.includes('german') || normalized.includes('deutsch')) code = 'de';
        else if (normalized.includes('italian') || normalized.includes('italiano')) code = 'it';
        else if (normalized.includes('japanese') || normalized.includes('nihongo')) code = 'ja';
        else if (normalized.includes('chinese') || normalized.includes('mandarin')) code = 'zh';
        else if (normalized.includes('portuguese') || normalized.includes('português')) code = 'pt';
        else if (normalized.includes('russian')) code = 'ru';
        else if (normalized.includes('korean')) code = 'ko';

        // Priority 1: Microsoft Natural Voice for the target language
        const natural = voices.find(v => v.lang.startsWith(code) && v.name.includes('Microsoft') && v.name.includes('Natural'));
        if (natural) return natural;

        // Priority 2: Any Microsoft Voice
        const microsoft = voices.find(v => v.lang.startsWith(code) && v.name.includes('Microsoft'));
        if (microsoft) return microsoft;

        // Priority 3: Google Voice
        const google = voices.find(v => v.lang.startsWith(code) && v.name.includes('Google'));
        if (google) return google;

        // Priority 4: Any matching voice
        return voices.find(v => v.lang.startsWith(code));
    }, [voices]);

    const handleSpeak = (text: string) => {
        if ('speechSynthesis' in window && data) {
            window.speechSynthesis.cancel();
            const utterance = new SpeechSynthesisUtterance(text);
            const voice = getVoiceForLanguage(data.targetLanguage);
            if (voice) {
                utterance.voice = voice;
                // utterance.rate = 0.9; // Slightly slower for learning
            }
            window.speechSynthesis.speak(utterance);
        }
    };

    if (isLoading) {
        return (
            <div className={`fixed inset-0 z-50 flex items-center justify-center bg-zinc-950 transition-opacity duration-500 ${isLoading ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
                 <div className="text-center space-y-6">
                    <div className="w-16 h-16 mx-auto border-4 border-blue-500/30 border-t-blue-500 rounded-full animate-spin"></div>
                    <div className="space-y-2">
                        <h3 className="text-xl font-bold text-white">Synthesizing Identity Profile</h3>
                        <p className="text-zinc-500 font-mono text-sm">Merging common lexicon with personal data...</p>
                    </div>
                 </div>
            </div>
        );
    }

    if (!data) return null;

    return (
        <div className={`fixed z-40 inset-0 md:inset-4 bg-[#09090b] md:rounded-2xl overflow-hidden flex flex-col transition-all duration-700 ${isFocused ? 'translate-y-0 opacity-100' : 'translate-y-full opacity-0 pointer-events-none'}`}>

            {/* Header */}
            <div className="flex items-center justify-between p-4 md:p-6 border-b border-zinc-800 bg-zinc-900/50 backdrop-blur-md">
                <div className="flex items-center space-x-4">
                    <button onClick={onReset} className="p-2 -ml-2 hover:bg-zinc-800 rounded-full text-zinc-400 hover:text-white transition-colors">
                        <ArrowPathIcon className="w-5 h-5" />
                    </button>
                    <div>
                        <h2 className="text-lg font-bold text-white">{data.identityTitle}</h2>
                        <p className="text-xs font-mono text-blue-400 uppercase tracking-wider">{data.targetLanguage} • Level 1</p>
                    </div>
                </div>
                <div className="flex space-x-2">
                    <button className="flex items-center space-x-2 px-3 py-1.5 bg-zinc-800 hover:bg-zinc-700 rounded-lg text-xs font-medium text-white transition-colors">
                        <ShareIcon className="w-4 h-4" />
                        <span className="hidden sm:inline">Share Profile</span>
                    </button>
                </div>
            </div>

            {/* Main Content */}
            <div className="flex-1 overflow-hidden flex flex-col md:flex-row">

                {/* Left Panel: Navigation & Progress */}
                <div className="w-full md:w-64 bg-zinc-900/30 border-r border-zinc-800 p-4 flex flex-row md:flex-col gap-2 shrink-0 overflow-x-auto md:overflow-visible">
                    <button 
                        onClick={() => setActiveTab('script')}
                        className={`flex items-center space-x-3 w-full p-3 rounded-lg text-sm font-medium transition-all ${activeTab === 'script' ? 'bg-blue-500/10 text-blue-400 border border-blue-500/20' : 'text-zinc-400 hover:bg-zinc-800'}`}
                    >
                        <SpeakerWaveIcon className="w-5 h-5" />
                        <span>Identity Script</span>
                    </button>
                    <button 
                        onClick={() => setActiveTab('vocab')}
                        className={`flex items-center space-x-3 w-full p-3 rounded-lg text-sm font-medium transition-all ${activeTab === 'vocab' ? 'bg-green-500/10 text-green-400 border border-green-500/20' : 'text-zinc-400 hover:bg-zinc-800'}`}
                    >
                        <BookOpenIcon className="w-5 h-5" />
                        <span>Vocabulary</span>
                    </button>
                </div>

                {/* Right Panel: Content */}
                <div className="flex-1 overflow-y-auto p-4 md:p-8 bg-dot-grid">
                    <div className="max-w-3xl mx-auto space-y-8">

                        {activeTab === 'script' && (
                            <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                                <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6 md:p-8 shadow-xl relative overflow-hidden">
                                    <div className="absolute top-0 right-0 p-4 opacity-10">
                                        <SpeakerWaveIcon className="w-24 h-24" />
                                    </div>

                                    <div className="relative z-10 space-y-6">
                                        <div className="space-y-4">
                                            <h3 className="text-zinc-500 text-sm font-mono uppercase tracking-wider">Your Story</h3>

                                            {/* Interactive Script Display */}
                                            <div className="text-2xl md:text-3xl font-medium leading-relaxed text-white">
                                                {targetWords.map((word, i) => (
                                                    <React.Fragment key={i}>
                                                        <span 
                                                            onClick={() => setHighlightedIndex(i)}
                                                            className={`cursor-pointer transition-colors duration-200 rounded px-1 -mx-1 ${
                                                                highlightedIndex === i 
                                                                    ? 'bg-blue-500/30 text-blue-200 shadow-[0_0_15px_rgba(59,130,246,0.2)]' 
                                                                    : 'hover:bg-white/10'
                                                            }`}
                                                        >
                                                            {word}
                                                        </span>
                                                        {i < targetWords.length - 1 && ' '}
                                                    </React.Fragment>
                                                ))}
                                            </div>

                                            <button 
                                                onClick={() => handleSpeak(data.script.target)}
                                                className="inline-flex items-center space-x-2 text-sm text-blue-400 hover:text-blue-300 font-medium"
                                            >
                                                <SpeakerWaveIcon className="w-4 h-4" />
                                                <span>Listen to pronunciation</span>
                                            </button>
                                        </div>

                                        <div className="h-px bg-zinc-800 w-full"></div>

                                        <div className="grid md:grid-cols-2 gap-6">
                                            <div>
                                                <h4 className="text-zinc-500 text-xs font-mono uppercase mb-2">Phonetic</h4>
                                                {/* Interactive Phonetic Display */}
                                                <div className="text-zinc-300 font-light leading-relaxed">
                                                    {phoneticWords.map((word, i) => (
                                                        <React.Fragment key={i}>
                                                            <span 
                                                                className={`transition-all duration-200 rounded px-1 -mx-1 ${
                                                                    highlightedIndex === i 
                                                                        ? 'bg-purple-500/30 text-purple-200 font-bold' 
                                                                        : 'italic'
                                                                }`}
                                                            >
                                                                {word}
                                                            </span>
                                                            {i < phoneticWords.length - 1 && ' '}
                                                        </React.Fragment>
                                                    ))}
                                                </div>
                                            </div>
                                            <div>
                                                <h4 className="text-zinc-500 text-xs font-mono uppercase mb-2">Translation</h4>
                                                <p className="text-zinc-400">{data.script.native}</p>
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                {/* Practice Section */}
                                <div className="mt-6">
                                    <h3 className="text-white font-bold mb-4 flex items-center gap-2">
                                        <div className="w-2 h-2 bg-red-500 rounded-full animate-pulse"></div>
                                        Action Phase
                                    </h3>
                                    <AudioRecorder />
                                    <p className="mt-3 text-sm text-zinc-500 italic">
                                        Challenge: {data.challenge}
                                    </p>
                                </div>
                            </div>
                        )}

                        {activeTab === 'vocab' && (
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
                                {data.vocabulary.map((item: any, idx: number) => (
                                    <div key={idx} className="bg-zinc-900 border border-zinc-800 p-4 rounded-xl flex items-center justify-between group hover:border-zinc-600 transition-colors">
                                        <div>
                                            <p className="text-lg font-bold text-white">{item.term}</p>
                                            <p className="text-sm text-zinc-400">{item.native}</p>
                                        </div>
                                        <span className={`text-[10px] font-mono uppercase px-2 py-1 rounded border ${
                                            item.type === 'Identity' ? 'bg-purple-500/10 text-purple-400 border-purple-500/20' :
                                            item.type === 'Action' ? 'bg-blue-500/10 text-blue-400 border-blue-500/20' :
                                            'bg-zinc-800 text-zinc-500 border-zinc-700'
                                        }`}>
