import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const GEMINI_MODEL = 'gemini-3-pro-preview';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `You are the "Self-Speak Engine", an advanced linguistic AI.

YOUR GOAL:
Generate a personalized "Day 1" language profile.

INPUT:
User profile data including: Target Language, Voice Gender, Profession, Passion, Motivation, and Personality.

OUTPUT FORMAT:
Return strictly a JSON object matching this schema:

{
  "targetLanguage": "string",
  "identityTitle": "string",
  "scriptSegments": [
    {
      "target": "string (Single word or small phrase in target language)",
      "phonetic": "string (Phonetic pronunciation)",
      "native": "string (English translation of this specific segment)"
    }
  ],
  "vocabulary": [
    {
      "term": "string",
      "native": "string",
      "type": "string"
    }
  ],
  "challenge": "string"
}

IMPORTANT:
1. **Grammatical Gender**: Ensure the "target" text strictly adheres to the user's selected Voice Gender (e.g., if Male, use "encantado"; if Female, use "encantada").
2. **Alignment**: Break the script into small, meaningful segments (usually 1-3 words) so that the 'target' and 'native' align perfectly in meaning.
   - Good: [{"target": "Me llamo", "native": "My name is"}, {"target": "Sofia", "native": "Sofia"}]
   - Bad: [{"target": "Me", "native": "My"}, {"target": "llamo", "native": "name"}] (if it breaks grammar context too much, prefer phrases)
3. **Hyper-Relevance**: Use words matching their profession/passion.

EXAMPLE INPUT:
Language: Spanish. Gender: Female. Job: Nurse.
EXAMPLE SEGMENTS:
[
  {"target": "Hola", "phonetic": "oh-la", "native": "Hello"},
  {"target": "soy", "phonetic": "soy", "native": "I am"},
  {"target": "enfermera", "phonetic": "en-fer-meh-ra", "native": "a nurse"}
]`;

export interface UserProfile {
  targetLanguage: string;
  gender: 'Male' | 'Female';
  profession: string;
  passion: string;
  motivation: string;
  personality: string;
}

export async function generateIdentityProfile(profile: UserProfile): Promise<string> {
  const prompt = `
    Target Language: ${profile.targetLanguage}
    Voice Gender: ${profile.gender}
    Profession: ${profile.profession}
    Passion: ${profile.passion}
    Motivation: ${profile.motivation}
    Personality/Traits: ${profile.personality}

    Generate the Self-Speak Profile JSON with scriptSegments.
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: {
        parts: [{ text: prompt }]
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        temperature: 0.4, 
      },
    });

    let text = response.text || "{}";
    text = text.replace(/^```json\s*/, '').replace(/^```\s*/, '').replace(/```$/, '');

    return text;
  } catch (error) {
    console.error("Gemini Generation Error:", error);
    throw error;
  }
}

