import React, { useState, useRef, useEffect, useMemo, useCallback } from 'react';
import { MicrophoneIcon, SpeakerWaveIcon, ArrowPathIcon, ShareIcon, BookOpenIcon, PlayIcon, StopIcon } from '@heroicons/react/24/solid';

interface LivePreviewProps {
  creation: any; // Using any for the JSON structure
  isLoading: boolean;
  isFocused: boolean;
  onReset: () => void;
}

const AudioRecorder = () => {
    const [isRecording, setIsRecording] = useState(false);
    const [audioBlob, setAudioBlob] = useState<Blob | null>(null);
    const mediaRecorderRef = useRef<MediaRecorder | null>(null);
    const chunksRef = useRef<Blob[]>([]);

    const startRecording = async () => {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            mediaRecorderRef.current = new MediaRecorder(stream);
            chunksRef.current = [];

            mediaRecorderRef.current.ondataavailable = (e) => {
                if (e.data.size > 0) chunksRef.current.push(e.data);
            };

            mediaRecorderRef.current.onstop = () => {
                const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
                setAudioBlob(blob);
                // Stop all tracks to release mic
                stream.getTracks().forEach(track => track.stop());
            };

            mediaRecorderRef.current.start();
            setIsRecording(true);
        } catch (err) {
            console.error("Error accessing microphone:", err);
            alert("Microphone access is needed to record your practice.");
        }
    };

    const stopRecording = () => {
        if (mediaRecorderRef.current && isRecording) {
            mediaRecorderRef.current.stop();
            setIsRecording(false);
        }
    };

    const playRecording = () => {
        if (audioBlob) {
            const url = URL.createObjectURL(audioBlob);
            const audio = new Audio(url);
            audio.play();
        }
    };

    return (
        <div className="flex items-center space-x-4 bg-zinc-900/50 p-4 rounded-xl border border-zinc-800">
            <button
                onClick={isRecording ? stopRecording : startRecording}
                className={`w-12 h-12 rounded-full flex items-center justify-center transition-all ${isRecording ? 'bg-red-500 animate-pulse' : 'bg-zinc-800 hover:bg-zinc-700 text-white'}`}
            >
                {isRecording ? <StopIcon className="w-6 h-6 text-white" /> : <MicrophoneIcon className="w-6 h-6" />}
            </button>
            <div className="flex-1">
                <div className="text-sm font-medium text-white">{isRecording ? "Recording..." : audioBlob ? "Recording Saved" : "Record your script"}</div>
                <div className="text-xs text-zinc-500">{isRecording ? "Speak clearly..." : audioBlob ? "Click play to listen" : "Press the mic to start"}</div>
            </div>
            {audioBlob && !isRecording && (
                <button onClick={playRecording} className="p-2 text-blue-400 hover:text-blue-300">
                    <PlayIcon className="w-8 h-8" />
                </button>
            )}
        </div>
    );
};

export const LivePreview: React.FC<LivePreviewProps> = ({ creation, isLoading, isFocused, onReset }) => {
    const [activeTab, setActiveTab] = useState<'script' | 'vocab'>('script');
    const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);
    const [highlightedIndex, setHighlightedIndex] = useState<number | null>(null);
    const [isPlaying, setIsPlaying] = useState(false);

    // Load voices
    useEffect(() => {
        const updateVoices = () => {
            const available = window.speechSynthesis.getVoices();
            if (available.length > 0) {
                setVoices(available);
            }
        };
        updateVoices();
        window.speechSynthesis.onvoiceschanged = updateVoices;
        return () => { window.speechSynthesis.onvoiceschanged = null; };
    }, []);

    // Parse creation content if it's a JSON string
    const data = useMemo(() => {
        if (!creation || !creation.html) return null;
        try {
            return JSON.parse(creation.html);
        } catch (e) {
            console.error("Failed to parse creation JSON", e);
            return null;
        }
    }, [creation]);

    // New Data Structure: Array of Segments
    const segments = useMemo(() => {
        if (data?.scriptSegments) return data.scriptSegments;
        // Fallback for old data structure
        if (data?.script?.target) {
            const targets = data.script.target.split(' ');
            const phonetics = data.script.phonetic.split(' ');
            // Native usually doesn't align 1:1, so we just make a dummy array for fallback
            return targets.map((t: string, i: number) => ({
                target: t,
                phonetic: phonetics[i] || '',
                native: i === 0 ? data.script.native : '' // Show full native on first word as fallback
            }));
        }
        return [];
    }, [data]);

    const getVoiceForLanguage = useCallback((langName: string, genderPreference?: 'Male' | 'Female') => {
        if (!voices.length) return null;

        const normalized = langName.toLowerCase();
        let code = 'en'; 

        if (normalized.includes('spanish') || normalized.includes('español')) code = 'es';
        else if (normalized.includes('french') || normalized.includes('français')) code = 'fr';
        else if (normalized.includes('german') || normalized.includes('deutsch')) code = 'de';
        else if (normalized.includes('italian') || normalized.includes('italiano')) code = 'it';
        else if (normalized.includes('japanese') || normalized.includes('nihongo')) code = 'ja';
        else if (normalized.includes('chinese') || normalized.includes('mandarin')) code = 'zh';
        else if (normalized.includes('portuguese') || normalized.includes('português')) code = 'pt';
        else if (normalized.includes('russian')) code = 'ru';
        else if (normalized.includes('korean')) code = 'ko';

        // Filter by language first
        const langVoices = voices.filter(v => v.lang.startsWith(code));

        // Helper to check gender
        const isMale = (name: string) => {
            const n = name.toLowerCase();
            return n.includes('male') || n.includes('david') || n.includes('mark') || n.includes('stefan') || n.includes('paul') || n.includes('ichiro') || n.includes('alvaro') || n.includes('jorge') || n.includes('guy') || n.includes('christopher') || n.includes('daniel') || n.includes('conrad');
        };
        const isFemale = (name: string) => {
            const n = name.toLowerCase();
            return n.includes('female') || n.includes('zira') || n.includes('hazel') || n.includes('heera') || n.includes('haruka') || n.includes('elvira') || n.includes('dalia') || n.includes('aria') || n.includes('michelle') || n.includes('elena') || n.includes('laura') || n.includes('julie');
        };

        let genderFiltered = langVoices;

        if (genderPreference) {
            const isPrefMale = genderPreference === 'Male';
            const matchesGender = langVoices.filter(v => isPrefMale ? isMale(v.name) : isFemale(v.name));

            // If we found voices matching the gender, prioritize them
            if (matchesGender.length > 0) {
                genderFiltered = matchesGender;
            } else {
                // If explicit gender not found in name, try to filter OUT the opposite gender
                const opposite = langVoices.filter(v => isPrefMale ? !isFemale(v.name) : !isMale(v.name));
                if (opposite.length > 0) genderFiltered = opposite;
            }
        }

        // Within the gender-filtered (or all) voices, find the best quality
        // Priority 1: Microsoft Natural
        const natural = genderFiltered.find(v => v.name.includes('Microsoft') && v.name.includes('Natural'));
        if (natural) return natural;

        // Priority 2: Microsoft
        const microsoft = genderFiltered.find(v => v.name.includes('Microsoft'));
        if (microsoft) return microsoft;

        // Priority 3: Google
        const google = genderFiltered.find(v => v.name.includes('Google'));
        if (google) return google;

        return genderFiltered[0] || langVoices[0];
    }, [voices]);

    const handleSpeakWhole = () => {
        if ('speechSynthesis' in window) {
            if (isPlaying) {
                window.speechSynthesis.cancel();
                setIsPlaying(false);
                return;
            }

            if (segments.length > 0) {
                window.speechSynthesis.cancel(); // Safety cancel
                const fullText = segments.map((s: any) => s.target).join(' ');
                const utterance = new SpeechSynthesisUtterance(fullText);
                const voice = getVoiceForLanguage(data.targetLanguage, data.gender);
                if (voice) utterance.voice = voice;

                utterance.onend = () => setIsPlaying(false);
                utterance.onerror = () => setIsPlaying(false);

                window.speechSynthesis.speak(utterance);
                setIsPlaying(true);
            }
        }
    };

    const handleSpeakWord = (word: string) => {
        if ('speechSynthesis' in window) {
            // If main playback is active, don't stop it, just pause logic would be complex.
            // Standard behavior: clicking a word stops the main playback and plays the word.
            if (isPlaying) {
                window.speechSynthesis.cancel();
                setIsPlaying(false);
            }
            window.speechSynthesis.cancel();
            const utterance = new SpeechSynthesisUtterance(word);
            const voice = getVoiceForLanguage(data.targetLanguage, data.gender); // Pass gender
            if (voice) utterance.voice = voice;
            window.speechSynthesis.speak(utterance);
        }
    };

    if (isLoading) {
        return (
            <div className={`fixed inset-0 z-50 flex items-center justify-center bg-zinc-950 transition-opacity duration-500 ${isLoading ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
