import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const GEMINI_MODEL = 'gemini-3-pro-preview';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `You are the "Self-Speak Engine", an advanced linguistic AI.

YOUR GOAL:
Generate a personalized "Day 1" language profile.

INPUT:
User profile data including: Target Language, Gender, Profession, Passion, Routine, Environment, Diet, Essentials, Motivation, and Personality.

OUTPUT FORMAT:
Return strictly a JSON object matching this schema:

{
  "targetLanguage": "string",
  "gender": "string (Male or Female)",
  "identityTitle": "string",
  "scriptSegments": [
    {
      "target": "string (The native script. Kanji/Kana for Japanese, Hanzi for Chinese, etc.)",
      "transliteration": "string (REQUIRED for non-Latin scripts: Romanized text e.g. Romaji, Pinyin)",
      "phonetic": "string (Phonetic pronunciation guide)",
      "native": "string (English translation of this specific segment)"
    }
  ],
  "vocabulary": [
    {
      "term": "string",
      "native": "string",
      "type": "string"
    }
  ],
  "challenge": "string"
}

IMPORTANT GUIDELINES:
1. **Tone & Sentence Structure**: NATURAL, FLUENT, and ARTICULATE.
   - **Do NOT embellish** with fake emotions or flowery, poetic adjectives (avoid "soulful", "magical", "tapestry").
   - **Do NOT be robotic** or overly simple. Avoid choppy, short sentences (avoid "I like coffee. It is good.").
   - **DO** write complete, interesting sentences that flow logically. Use connecting words (because, so, although, while) to sound like a fluent adult.
   - **Goal**: Sound like a real person explaining their life to a friend—matter-of-fact but detailed and engaging.

   - **Bad (Embellished)**: "I traverse the concrete jungle with a heart full of dreams, seeking the nectar of life."
   - **Bad (Robotic)**: "I live in the city. I walk to work. I like my job."
   - **Good (Target)**: "Since I live in a busy part of the city, I usually walk to work, which gives me time to listen to music and clear my head before the day begins."

2. **Content & Vocabulary**: 
   - **Narrative**: The script must be a rich narrative (approx. 200-250 words) covering specific life details.
   - **Vocabulary List**: The "vocabulary" array MUST be comprehensive (12-20 items).
     - **EXTRACT ALL** specific nouns, verbs, and adjectives used in the script that relate to:
       1. **Profession & Tools** (e.g., 'Laptop', 'Scalpel', 'Code', 'Meeting')
       2. **Passion & Hobbies** (e.g., 'Guitar', 'Hiking boots', 'Canvas', 'Controller')
       3. **Routine & Diet** (e.g., 'Coffee', 'Avocado', 'Train', 'Gym', 'Subway')
       4. **Environment** (e.g., 'Garden', 'Skyscraper', 'River', 'Studio')
       5. **Personality/Vibe** (e.g., 'Curious', 'Energetic', 'Calm')

3. **Grammatical Gender**: Ensure the "target" text strictly adheres to the user's selected Voice Gender.

4. **Alignment**: Break the script into small, meaningful segments (usually 1-3 words) so that the 'target' and 'native' align perfectly in meaning, even within complex sentences.

EXAMPLE INPUT:
Language: Japanese. Gender: Female. Job: Designer.
EXAMPLE SEGMENTS:
[
  {"target": "こんにちは", "transliteration": "Konnichiwa", "phonetic": "kon-nee-chee-wah", "native": "Hello"},
  {"target": "私は", "transliteration": "watashi wa", "phonetic": "wah-tah-shee wah", "native": "I am"},
  {"target": "デザイナーです", "transliteration": "dezainā desu", "phonetic": "deh-zai-nah dess", "native": "a designer"}
]`;

export interface UserProfile {
  targetLanguage: string;
  gender: 'Male' | 'Female';
  profession: string;
  passion: string;
  routine: string;
  environment: string;
  diet: string;
  essentials: string;
  motivation: string;
  personality: string;
}

export async function generateIdentityProfile(profile: UserProfile): Promise<string> {
  const prompt = `
    Target Language: ${profile.targetLanguage}
    Voice Gender: ${profile.gender}
    Profession: ${profile.profession}
    Passion: ${profile.passion}
    Daily Routine: ${profile.routine}
    Living Environment: ${profile.environment}
    Diet/Favorite Foods: ${profile.diet}
    Essential Objects: ${profile.essentials}
    Motivation: ${profile.motivation}
    Personality/Traits: ${profile.personality}

    Generate the Self-Speak Profile JSON with scriptSegments. 
    Ensure the narrative flows naturally with interesting, complete sentences, but keep the tone grounded and realistic.
    For non-Latin languages (Japanese, Chinese, etc), YOU MUST provide the 'transliteration' field.
    Ensure the vocabulary list is extensive (12-20 words) and covers the specific inputs provided (tools, passions, foods).
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: {
        parts: [{ text: prompt }]
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        temperature: 0.4, // Slight increase to allow for better sentence formulation while keeping facts grounded
      },
    });

    let text = response.text || "{}";
    text = text.replace(/^```json\s*/, '').replace(/^```\s*/, '').replace(/```$/, '');

    return text;
  } catch (error) {
    console.error("Gemini Generation Error:", error);
    throw error;
  }
}

