                    </button>
                    <div>
                        <h2 className="text-lg font-bold text-white">{data.identityTitle}</h2>
                        <p className="text-xs font-mono text-blue-400 uppercase tracking-wider">{data.targetLanguage} • Level 1</p>
                    </div>
