                                                <div className="text-zinc-400 font-light text-lg leading-relaxed select-none">
                                                    {segments.map((seg: any, i: number) => (
                                                        <React.Fragment key={i}>
                                                            <span 
                                                                className={`transition-all duration-200 rounded px-1 -mx-1 inline-block ${
                                                                    highlightedIndex === i 
                                                                        ? 'bg-purple-500/20 text-purple-300 font-bold scale-105' 
                                                                        : 'italic'
                                                                }`}
                                                            >
                                                                {hasTransliteration ? seg.target : seg.phonetic}
                                                            </span>
                                                            {i < segments.length - 1 && ' '}
                                                        </React.Fragment>
                                                    ))}
                                                </div>
                                            </div>
                                            <div>
                                                <h4 className="text-zinc-500 text-xs font-mono uppercase mb-3">Translation</h4>
                                                <div className="text-zinc-400 font-light text-lg leading-relaxed select-none">
                                                    {segments.map((seg: any, i: number) => (
                                                        <React.Fragment key={i}>
                                                            <span 
                                                                className={`transition-all duration-200 rounded px-1 -mx-1 inline-block ${
                                                                    highlightedIndex === i 
                                                                        ? 'bg-green-500/20 text-green-300 font-medium scale-105' 
                                                                        : ''
                                                                }`}
                                                            >
                                                                {seg.native}
                                                            </span>
                                                            {i < segments.length - 1 && ' '}
                                                        </React.Fragment>
                                                    ))}
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                <div className="mt-8">
                                    <h3 className="text-white font-bold mb-4 flex items-center gap-2">
