                                                        'bg-zinc-800 text-zinc-500 border-zinc-700'
                                                    }`}>
                                                        {item.type}
                                                    </span>
                                                    <SpeakerWaveIcon className="w-3 h-3 text-zinc-700 group-hover:text-blue-500 transition-colors" />
                                                </div>
                                                <p className="text-xl font-bold text-white group-hover:text-blue-400 transition-colors">{item.term}</p>
                                                {item.transliteration && (
                                                    <p className="text-xs font-mono text-zinc-500 italic">{item.transliteration}</p>
                                                )}
                                            </div>
                                            <div className="mt-4 pt-4 border-t border-zinc-800/50">
                                                <p className="text-sm text-zinc-400 font-medium">{item.native}</p>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}

                    </div>
                </div>
            </div>
        </div>
    );
};

