  { id: 'stories', question: "Share a unique quirk or story about yourself.", placeholder: "e.g., I collect vintage spoons, I once met a bear" },
  { id: 'motivation', question: "Why learn this language now?", placeholder: "e.g., To speak with my grandmother, Travel to Tokyo" },
  { id: 'personality', question: "Describe your vibe in 3 words.", placeholder: "e.g., Energetic, Curious, Calm" }
];

export const InputArea: React.FC<InputAreaProps> = ({ onGenerate, isGenerating, disabled = false }) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState<any>({});
  const [isFocused, setIsFocused] = useState(false);
  const [isMusicPlaying, setIsMusicPlaying] = useState(false);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData({ ...formData, [STEPS[currentStep].id]: e.target.value });
  };

  const handleSelectChange = (value: string) => {
    setFormData({ ...formData, [STEPS[currentStep].id]: value });
  };

  const handleNext = () => {
    if (!formData[STEPS[currentStep].id]) return;

    // Auto-start music on the first 'Next' click (User Gesture)
    if (currentStep === 0 && !isMusicPlaying) {
      setIsMusicPlaying(true);
    }

    if (currentStep < STEPS.length - 1) {
      setCurrentStep(prev => prev + 1);
    } else {
      onGenerate(formData as UserProfile);
    }
  };

  const handleBack = () => {
    if (currentStep > 0) {
      setCurrentStep(prev => prev - 1);
    }
  };

  const handleReset = () => {
    if (confirm("Are you sure you want to start over? This will clear all your answers.")) {
      setFormData({});
      setCurrentStep(0);
      setIsMusicPlaying(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleNext();
    }
  };

  const progress = ((currentStep + 1) / STEPS.length) * 100;
  const currentStepData = STEPS[currentStep];

  return (
    <div className="w-full max-w-2xl mx-auto">
      <div 
        className={`
          relative bg-zinc-900/50 backdrop-blur-xl border border-zinc-800 rounded-2xl p-8 md:p-12
          transition-all duration-500
          ${isFocused ? 'ring-2 ring-blue-500/20 border-blue-500/50 shadow-2xl shadow-blue-500/10' : 'hover:border-zinc-700'}
        `}
      >
        {/* 
            Cloaked Ambiance Player
            - We place this INSIDE the card so it stays 'in viewport' for browser visibility checks.
            - We use opacity 0.01 instead of 0 to prevent browsers from marking it as 'hidden'.
            - We use absolute inset-0 to give it a substantial size (matching the card).
        */}
        {isMusicPlaying && !disabled && (
          <div className="absolute inset-0 w-full h-full opacity-[0.01] pointer-events-none -z-10 overflow-hidden">
            <iframe 
              src="https://www.udio.com/embed/iXaYLknwafhTphM8rbc9Nt?autoplay=1" 
              width="100%" 
              height="100%"
              allow="autoplay; encrypted-media"
              title="Identity Ambiance"
              frameBorder="0"
            />
          </div>
        )}

        {/* Progress Bar */}
        <div className="absolute top-0 left-0 right-0 h-1 bg-zinc-800 rounded-t-2xl overflow-hidden">
            <div 
                className="h-full bg-gradient-to-r from-blue-500 to-green-400 transition-all duration-500 ease-out"
                style={{ width: `${progress}%` }}
            ></div>
        </div>

        {/* Step Indicator & Music Toggle */}
        <div className="mb-8 flex items-center justify-between text-xs font-mono uppercase tracking-wider text-zinc-500">
            <div className="flex items-center space-x-2">
              <span>Step {currentStep + 1} of {STEPS.length}</span>
              {currentStep > 0 && (
                <button 
                  onClick={handleReset}
                  className="ml-4 flex items-center space-x-1 text-zinc-600 hover:text-red-400 transition-colors"
                >
                  <ArrowPathIcon className="w-3 h-3" />
                  <span>Start Over</span>
                </button>
              )}
            </div>

            <div className="flex items-center space-x-4">
              <button 
                onClick={() => setIsMusicPlaying(!isMusicPlaying)}
                className={`flex items-center space-x-2 transition-all duration-300 ${isMusicPlaying ? 'text-blue-400' : 'text-zinc-600 hover:text-zinc-400'}`}
                title={isMusicPlaying ? "Stop Ambiance" : "Play Ambiance"}
              >
                <div className="relative">
                  {isMusicPlaying ? (
                    <>
                      <SpeakerWaveIcon className="w-4 h-4 animate-pulse" />
                      <div className="absolute inset-0 bg-blue-500/20 blur-sm animate-pulse rounded-full"></div>
                    </>
                  ) : (
                    <SpeakerXMarkIcon className="w-4 h-4" />
                  )}
                </div>
                <span className="text-[10px] hidden sm:inline">{isMusicPlaying ? 'Vibe On' : 'Vibe Off'}</span>
              </button>
              <span className="text-zinc-700">|</span>
              <span>Identity Intake</span>
            </div>
        </div>

        {/* Question */}
        <div className="min-h-[160px] flex flex-col justify-center">
            <h3 className="text-2xl md:text-3xl font-bold text-white mb-6 animate-in fade-in slide-in-from-left-4 duration-300" key={currentStepData.question}>
                {currentStepData.question}
            </h3>

            <div className="relative">
                {currentStepData.type === 'select' ? (
                  <div className="flex gap-4">
                    {currentStepData.options?.map((opt) => (
                      <button
                        key={opt}
                        onClick={() => handleSelectChange(opt)}
                        className={`
                          px-6 py-3 rounded-xl border-2 text-lg font-medium transition-all duration-200
                          ${formData[currentStepData.id] === opt 
                            ? 'border-blue-500 bg-blue-500/10 text-white shadow-[0_0_20px_rgba(59,130,246,0.2)]' 
                            : 'border-zinc-700 text-zinc-400 hover:border-zinc-500 hover:text-white'}
                        `}
                      >
                        {opt}
                      </button>
                    ))}
                  </div>
                ) : (
                  <input
                      type="text"
                      value={formData[currentStepData.id] || ''}
                      onChange={handleInputChange}
                      onKeyDown={handleKeyDown}
                      onFocus={() => setIsFocused(true)}
                      onBlur={() => setIsFocused(false)}
                      placeholder={currentStepData.placeholder}
                      className="w-full bg-transparent border-b-2 border-zinc-700 text-xl md:text-2xl text-white pb-4 placeholder-zinc-600 focus:outline-none focus:border-blue-500 transition-colors"
                      disabled={isGenerating || disabled}
                      autoFocus
                  />
                )}
            </div>
        </div>

        {/* Navigation */}
        <div className="mt-10 flex justify-between items-center">
            <div>
              {currentStep > 0 && (
                <button
                  onClick={handleBack}
                  disabled={isGenerating}
                  className="group flex items-center space-x-2 px-6 py-3 rounded-full font-medium text-zinc-400 hover:text-white border border-zinc-800 hover:border-zinc-600 transition-all duration-300"
                >
                  <ArrowLeftIcon className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />
                  <span>Back</span>
                </button>
              )}
            </div>

            <button
                onClick={handleNext}
                disabled={!formData[currentStepData.id] || isGenerating}
                className={`
                    group flex items-center space-x-2 px-8 py-3 rounded-full font-medium transition-all duration-300
                    ${!formData[currentStepData.id] 
                        ? 'bg-zinc-800 text-zinc-500 cursor-not-allowed' 
                        : 'bg-white text-black hover:scale-105 shadow-lg shadow-white/10'}
                `}
            >
                <span>{currentStep === STEPS.length - 1 ? (isGenerating ? 'Synthesizing...' : 'Generate Profile') : 'Next'}</span>
                {isGenerating ? (
                    <SparklesIcon className="w-5 h-5 animate-spin" />
                ) : (
                    <ArrowRightIcon className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
                )}
            </button>
        </div>
      </div>
    </div>
  );
};

