  { id: 'personality', question: "Describe your vibe in 3 words.", placeholder: "e.g., Energetic, Curious, Calm" }
];

// Reference to your 770kb MP3 file
const VIBE_MP3_PATH = './vibe.mp3';

export const InputArea: React.FC<InputAreaProps> = ({ onGenerate, isGenerating, disabled = false }) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState<any>({});
  const [isFocused, setIsFocused] = useState(false);
  const [isMusicPlaying, setIsMusicPlaying] = useState(false);

  // Audio Controller State
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    // Initialize audio object
    const audio = new Audio(VIBE_MP3_PATH);
    audio.loop = true;
    audio.volume = 0; // Start at 0 for fade-in
    audioRef.current = audio;

    return () => {
      audio.pause();
      audio.src = '';
    };
  }, []);

  const fadeInAudio = () => {
    if (!audioRef.current) return;
    const audio = audioRef.current;
    audio.play().catch(e => console.error("Playback failed:", e));

    let vol = 0;
    const interval = setInterval(() => {
      if (vol < 0.15) { // Max volume 15% to stay ambient
        vol += 0.01;
        audio.volume = vol;
      } else {
        clearInterval(interval);
      }
    }, 100);
  };

  const fadeOutAudio = () => {
    if (!audioRef.current) return;
    const audio = audioRef.current;
    let vol = audio.volume;
    const interval = setInterval(() => {
      if (vol > 0.01) {
        vol -= 0.01;
        audio.volume = vol;
      } else {
        audio.pause();
        clearInterval(interval);
      }
    }, 100);
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData({ ...formData, [STEPS[currentStep].id]: e.target.value });
  };

  const handleSelectChange = (value: string) => {
    setFormData({ ...formData, [STEPS[currentStep].id]: value });
  };

  const handleNext = () => {
    if (!formData[STEPS[currentStep].id]) return;

    // Auto-start music on the first 'Next' click (User Interaction granted)
    if (currentStep === 0 && !isMusicPlaying) {
      setIsMusicPlaying(true);
      fadeInAudio();
    }

    if (currentStep < STEPS.length - 1) {
      setCurrentStep(prev => prev + 1);
    } else {
      onGenerate(formData as UserProfile);
      setIsMusicPlaying(false);
      fadeOutAudio();
    }
  };

  const handleBack = () => {
    if (currentStep > 0) {
      setCurrentStep(prev => prev - 1);
    }
  };

  const handleReset = () => {
    if (confirm("Are you sure you want to start over? This will clear all your answers.")) {
      setFormData({});
      setCurrentStep(0);
      setIsMusicPlaying(false);
      fadeOutAudio();
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleNext();
    }
  };

  const toggleVibe = () => {
    if (isMusicPlaying) {
      setIsMusicPlaying(false);
      fadeOutAudio();
    } else {
      setIsMusicPlaying(true);
      fadeInAudio();
    }
  };

  const progress = ((currentStep + 1) / STEPS.length) * 100;
  const currentStepData = STEPS[currentStep];

  return (
    <div className="w-full max-w-2xl mx-auto">
      <div 
        className={`
          relative bg-zinc-900/50 backdrop-blur-xl border border-zinc-800 rounded-2xl p-8 md:p-12
          transition-all duration-500
          ${isFocused ? 'ring-2 ring-blue-500/20 border-blue-500/50 shadow-2xl shadow-blue-500/10' : 'hover:border-zinc-700'}
        `}
      >
        {/* Progress Bar */}
        <div className="absolute top-0 left-0 right-0 h-1 bg-zinc-800 rounded-t-2xl overflow-hidden">
            <div 
                className="h-full bg-gradient-to-r from-blue-500 to-green-400 transition-all duration-500 ease-out"
                style={{ width: `${progress}%` }}
            ></div>
        </div>

        {/* Step Indicator & Music Toggle */}
        <div className="mb-8 flex items-center justify-between text-xs font-mono uppercase tracking-wider text-zinc-500">
            <div className="flex items-center space-x-2">
              <span>Step {currentStep + 1} of {STEPS.length}</span>
              {currentStep > 0 && (
                <button 
                  onClick={handleReset}
                  className="ml-4 flex items-center space-x-1 text-zinc-600 hover:text-red-400 transition-colors"
                >
                  <ArrowPathIcon className="w-3 h-3" />
                  <span>Start Over</span>
                </button>
              )}
            </div>

            <div className="flex items-center space-x-4">
              <button 
                onClick={toggleVibe}
                className={`flex items-center space-x-2 transition-all duration-300 ${isMusicPlaying ? 'text-blue-400' : 'text-zinc-600 hover:text-zinc-400'}`}
                title={isMusicPlaying ? "Stop Ambiance" : "Play Ambiance"}
              >
                <div className="relative">
                  {isMusicPlaying ? (
                    <>
                      <SpeakerWaveIcon className="w-4 h-4 animate-pulse" />
                      <div className="absolute inset-0 bg-blue-500/20 blur-sm animate-pulse rounded-full"></div>
                    </>
                  ) : (
                    <SpeakerXMarkIcon className="w-4 h-4" />
                  )}
                </div>
                <span className="text-[10px] hidden sm:inline">{isMusicPlaying ? 'Vibe Active' : 'Vibe Muted'}</span>
              </button>
              <span className="text-zinc-700">|</span>
              <span>Identity Intake</span>
            </div>
        </div>

        {/* Question */}
        <div className="min-h-[160px] flex flex-col justify-center">
