  { id: 'personality', question: "Describe your vibe in 3 words.", placeholder: "e.g., Energetic, Curious, Calm" }
];

// Main ambiance file - must be in project root
const VIBE_MP3_PATH = 'vibe.mp3';
const TARGET_VOLUME = 0.25; // 25% default volume

export const InputArea: React.FC<InputAreaProps> = ({ onGenerate, isGenerating, disabled = false }) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState<any>({});
  const [isFocused, setIsFocused] = useState(false);
  const [isMusicPlaying, setIsMusicPlaying] = useState(false);
  const [audioError, setAudioError] = useState(false);

  // Audio Refs
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const fadeIntervalRef = useRef<number | null>(null);

  useEffect(() => {
    // Initialize audio object
    const audio = new Audio();
    audio.src = VIBE_MP3_PATH;
    audio.loop = true;
    audio.volume = 0;
    audio.preload = 'auto';

    audio.onerror = () => {
      console.warn("Vibe MP3 loading failed at root directory. Ambiance disabled.");
      setAudioError(true);
    };

    audioRef.current = audio;

    return () => {
      if (fadeIntervalRef.current) window.clearInterval(fadeIntervalRef.current);
      audio.pause();
      audio.src = '';
    };
  }, []);

  const fadeInAudio = () => {
    if (fadeIntervalRef.current) window.clearInterval(fadeIntervalRef.current);
    if (!audioRef.current || audioError) return;

    const audio = audioRef.current;

    audio.play().catch(e => {
      console.warn("User gesture required for playback start.");
    });

    let vol = audio.volume;
    fadeIntervalRef.current = window.setInterval(() => {
      if (vol < TARGET_VOLUME) {
        vol += 0.01;
        audio.volume = Math.min(vol, TARGET_VOLUME);
      } else {
        if (fadeIntervalRef.current) window.clearInterval(fadeIntervalRef.current);
      }
    }, 50);
  };

  const fadeOutAudio = () => {
    if (fadeIntervalRef.current) window.clearInterval(fadeIntervalRef.current);
    if (!audioRef.current) return;

    const audio = audioRef.current;
    let vol = audio.volume;
    fadeIntervalRef.current = window.setInterval(() => {
      if (vol > 0.01) {
        vol -= 0.01;
        audio.volume = Math.max(vol, 0);
      } else {
        audio.pause();
        audio.volume = 0;
        if (fadeIntervalRef.current) window.clearInterval(fadeIntervalRef.current);
      }
    }, 50);
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData({ ...formData, [STEPS[currentStep].id]: e.target.value });
  };

  const handleSelectChange = (value: string) => {
    setFormData({ ...formData, [STEPS[currentStep].id]: value });
  };

  const handleNext = () => {
    if (!formData[STEPS[currentStep].id]) return;

    // Engagement check: Audio starts on first meaningful interaction
    if (currentStep === 0 && !isMusicPlaying) {
      setIsMusicPlaying(true);
      fadeInAudio();
    }

    if (currentStep < STEPS.length - 1) {
      setCurrentStep(prev => prev + 1);
    } else {
      onGenerate(formData as UserProfile);
      setIsMusicPlaying(false);
      fadeOutAudio();
    }
  };

  const handleBack = () => {
    if (currentStep > 0) {
      setCurrentStep(prev => prev - 1);
    }
  };

  const handleReset = () => {
    // Explicit warning for aborting progress
    const confirmAbort = window.confirm(
      "⚠ WARNING: ABORTING DATA ENTRY\n\nThis will permanently delete all information you have entered in the current sequence. Are you sure you want to reset?"
    );

    if (confirmAbort) {
      setFormData({});
      setCurrentStep(0);
      setIsMusicPlaying(false);
      fadeOutAudio();
    }
  };

  const toggleVibe = () => {
    if (audioError) {
      alert("Missing 'vibe.mp3' in project root. Ambiance is unavailable.");
      return;
    }

    if (isMusicPlaying) {
      setIsMusicPlaying(false);
      fadeOutAudio();
    } else {
      setIsMusicPlaying(true);
      fadeInAudio();
    }
  };

  const progress = ((currentStep + 1) / STEPS.length) * 100;
  const currentStepData = STEPS[currentStep];

  return (
    <div className="w-full max-w-2xl mx-auto">
      <div 
        className={`
          relative bg-zinc-900/50 backdrop-blur-xl border border-zinc-800 rounded-2xl p-8 md:p-12
          transition-all duration-500
          ${isFocused ? 'ring-2 ring-blue-500/20 border-blue-500/50 shadow-2xl shadow-blue-500/10' : 'hover:border-zinc-700'}
        `}
      >
        {/* Progress Bar */}
        <div className="absolute top-0 left-0 right-0 h-1 bg-zinc-800 rounded-t-2xl overflow-hidden">
            <div 
                className="h-full bg-gradient-to-r from-blue-500 to-green-400 transition-all duration-500 ease-out"
                style={{ width: `${progress}%` }}
            ></div>
        </div>

        {/* Header / Meta */}
        <div className="mb-8 flex items-center justify-between text-[10px] font-mono uppercase tracking-widest text-zinc-500">
            <div className="flex items-center space-x-2">
              <span className="text-zinc-400">Entry Seq {currentStep + 1}/{STEPS.length}</span>
              {currentStep > 0 && (
                <button 
                  onClick={handleReset}
                  className="ml-4 flex items-center space-x-1 text-zinc-600 hover:text-red-500 transition-colors"
                  title="Wipe data and restart"
                >
                  <ArrowPathIcon className="w-3 h-3" />
                  <span>Abort Process</span>
                </button>
              )}
            </div>

            <div className="flex items-center space-x-4">
              <button 
                onClick={toggleVibe}
                className={`flex items-center space-x-2 transition-all duration-300 ${isMusicPlaying ? 'text-blue-400' : 'text-zinc-600 hover:text-zinc-400'}`}
                title={isMusicPlaying ? "Mute Atmosphere" : "Unmute Atmosphere"}
              >
                <div className="relative">
                  {isMusicPlaying ? (
                    <>
                      <SpeakerWaveIcon className="w-4 h-4 animate-pulse" />
                      <div className="absolute inset-0 bg-blue-500/20 blur-sm animate-pulse rounded-full"></div>
                    </>
                  ) : (
                    <SpeakerXMarkIcon className="w-4 h-4" />
                  )}
                </div>
                <span className="hidden sm:inline">
                  {audioError ? 'No Vibe Found' : isMusicPlaying ? `Atmosphere @ ${Math.round(TARGET_VOLUME * 100)}%` : 'Silence Active'}
                </span>
              </button>
              <span className="text-zinc-800">|</span>
              <span className="text-zinc-600">Secure Intake</span>
            </div>
        </div>

        {/* Question Area */}
        <div className="min-h-[160px] flex flex-col justify-center">
            <h3 className="text-2xl md:text-3xl font-bold text-white mb-6 animate-in fade-in slide-in-from-left-4 duration-500" key={currentStepData.question}>
                {currentStepData.question}
            </h3>

            <div className="relative">
                {currentStepData.type === 'select' ? (
                  <div className="flex gap-4">
                    {currentStepData.options?.map((opt) => (
                      <button
                        key={opt}
                        onClick={() => handleSelectChange(opt)}
                        className={`
                          px-6 py-3 rounded-xl border-2 text-lg font-medium transition-all duration-300
                          ${formData[currentStepData.id] === opt 
                            ? 'border-blue-500 bg-blue-500/10 text-white shadow-[0_0_30px_rgba(59,130,246,0.1)]' 
                            : 'border-zinc-800 text-zinc-500 hover:border-zinc-700 hover:text-zinc-300'}
                        `}
