const VIBE_MP3_PATH = 'vibe.mp3';
const TARGET_VOLUME = 0.25;

export const InputArea: React.FC<InputAreaProps> = ({ onGenerate, isGenerating, disabled = false }) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState<any>({});
  const [isFocused, setIsFocused] = useState(false);
  const [isMusicPlaying, setIsMusicPlaying] = useState(false);
  const [audioError, setAudioError] = useState(false);
  const [showConfirmReset, setShowConfirmReset] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const fadeIntervalRef = useRef<number | null>(null);

  useEffect(() => {
    const audio = new Audio();
    audio.src = VIBE_MP3_PATH;
    audio.loop = true;
    audio.volume = 0;
    audio.preload = 'auto';

    audio.onerror = () => {
      console.warn("Vibe MP3 loading failed.");
      setAudioError(true);
    };

    audioRef.current = audio;

    return () => {
      if (fadeIntervalRef.current) window.clearInterval(fadeIntervalRef.current);
      audio.pause();
      audio.src = '';
    };
  }, []);

  const fadeInAudio = () => {
    if (fadeIntervalRef.current) window.clearInterval(fadeIntervalRef.current);
    if (!audioRef.current || audioError) return;

    const audio = audioRef.current;
    audio.play().catch(() => console.warn("Intercation required for audio."));

    let vol = audio.volume;
    fadeIntervalRef.current = window.setInterval(() => {
      if (vol < TARGET_VOLUME) {
        vol += 0.01;
        audio.volume = Math.min(vol, TARGET_VOLUME);
      } else {
        if (fadeIntervalRef.current) window.clearInterval(fadeIntervalRef.current);
      }
    }, 50);
  };

  const fadeOutAudio = () => {
    if (fadeIntervalRef.current) window.clearInterval(fadeIntervalRef.current);
    if (!audioRef.current) return;

    const audio = audioRef.current;
    let vol = audio.volume;
    fadeIntervalRef.current = window.setInterval(() => {
      if (vol > 0.01) {
        vol -= 0.01;
        audio.volume = Math.max(vol, 0);
      } else {
        audio.pause();
        audio.volume = 0;
        if (fadeIntervalRef.current) window.clearInterval(fadeIntervalRef.current);
      }
    }, 50);
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData({ ...formData, [STEPS[currentStep].id]: e.target.value });
  };

  const handleSelectChange = (value: string) => {
    setFormData({ ...formData, [STEPS[currentStep].id]: value });
  };

  const handleNext = () => {
    if (!formData[STEPS[currentStep].id]) return;

    if (currentStep === 0 && !isMusicPlaying) {
      setIsMusicPlaying(true);
      fadeInAudio();
    }

    if (currentStep < STEPS.length - 1) {
      setCurrentStep(prev => prev + 1);
    } else {
      onGenerate(formData as UserProfile);
      setIsMusicPlaying(false);
      fadeOutAudio();
    }
  };

  const handleBack = () => {
    if (currentStep > 0) {
      setCurrentStep(prev => prev - 1);
    }
  };

  const handleReset = () => {
    setFormData({});
    setCurrentStep(0);
    setIsMusicPlaying(false);
    setShowConfirmReset(false);
    fadeOutAudio();
  };

  const toggleVibe = () => {
    if (audioError) {
      alert("Error: 'vibe.mp3' not found in root directory.");
      return;
    }
    if (isMusicPlaying) {
      setIsMusicPlaying(false);
      fadeOutAudio();
    } else {
      setIsMusicPlaying(true);
      fadeInAudio();
    }
  };

  const progress = ((currentStep + 1) / STEPS.length) * 100;
  const currentStepData = STEPS[currentStep];

  return (
    <div className="w-full max-w-2xl mx-auto">
      <div 
        className={`
          relative bg-zinc-900/50 backdrop-blur-xl border border-zinc-800 rounded-2xl p-8 md:p-12
          transition-all duration-500
          ${isFocused ? 'ring-2 ring-blue-500/20 border-blue-500/50 shadow-2xl shadow-blue-500/10' : 'hover:border-zinc-700'}
        `}
      >
        <div className="absolute top-0 left-0 right-0 h-1 bg-zinc-800 rounded-t-2xl overflow-hidden">
            <div 
                className="h-full bg-gradient-to-r from-blue-500 to-green-400 transition-all duration-500 ease-out"
                style={{ width: `${progress}%` }}
            ></div>
        </div>

        <div className="mb-8 flex items-center justify-between text-[10px] font-mono uppercase tracking-widest text-zinc-500">
            <div className="flex items-center space-x-2">
              <span className="text-zinc-400 shrink-0">Seq {currentStep + 1}/{STEPS.length}</span>

              {currentStep > 0 && (
                <div className="ml-4 flex items-center">
                  {showConfirmReset ? (
                    <div className="flex items-center space-x-2 animate-in fade-in slide-in-from-left-2 duration-300">
                      <span className="text-red-400 font-bold">Confirm Abort?</span>
                      <button 
                        onClick={handleReset}
                        className="p-1 bg-red-500/20 hover:bg-red-500/40 border border-red-500/40 rounded text-red-400 transition-colors"
                      >
                        <CheckIcon className="w-3 h-3" />
                      </button>
                      <button 
                        onClick={() => setShowConfirmReset(false)}
                        className="p-1 bg-zinc-800 hover:bg-zinc-700 border border-zinc-700 rounded text-zinc-400 transition-colors"
                      >
                        <XMarkIcon className="w-3 h-3" />
                      </button>
                    </div>
                  ) : (
                    <button 
                      onClick={() => setShowConfirmReset(true)}
                      className="flex items-center space-x-1 text-zinc-600 hover:text-red-500 transition-all duration-200"
                    >
                      <ArrowPathIcon className="w-3 h-3" />
                      <span>Abort</span>
                    </button>
                  )}
                </div>
              )}
            </div>

            <div className="flex items-center space-x-4">
              <button 
                onClick={toggleVibe}
                className={`flex items-center space-x-2 transition-all duration-300 ${isMusicPlaying ? 'text-blue-400' : 'text-zinc-600 hover:text-zinc-400'}`}
              >
                <div className="relative">
                  {isMusicPlaying ? (
                    <>
                      <SpeakerWaveIcon className="w-4 h-4 animate-pulse" />
                      <div className="absolute inset-0 bg-blue-500/20 blur-sm animate-pulse rounded-full"></div>
                    </>
                  ) : (
                    <SpeakerXMarkIcon className="w-4 h-4" />
                  )}
                </div>
                <span className="hidden sm:inline font-bold">
                  {audioError ? 'Audio Fail' : isMusicPlaying ? `Live ${Math.round(TARGET_VOLUME * 100)}%` : 'Muted'}
